query:
SELECT COUNT(*) as with_matches FROM campaignContacts WHERE matchedProjectCount > 0;
SELECT DISTINCT company, title, email, score, tier, titleRelevance, matchedProjectCount 
FROM campaignContacts 
WHERE titleRelevance = 'blasting_specialist' AND email IS NOT NULL
ORDER BY score DESC LIMIT 15;

